def flatten_json_values(nested_data):
    result = []
    for item in nested_data:
        if isinstance(item, list):
            for sub_item in item:
                result.append(sub_item)
        else:
            result.append(item)
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_mixed_values_and_sublists(self):
        self.assertEqual(flatten_json_values([1, [2, 3], 4]), [1, 2, 3, 4])

    def test_all_sublists(self):
        self.assertEqual(flatten_json_values([[1, 2], [3, 4]]), [1, 2, 3, 4])

    def test_no_nesting(self):
        self.assertEqual(flatten_json_values([1, 2, 3]), [1, 2, 3])

    def test_hidden_empty_list(self):
        self.assertEqual(flatten_json_values([]), [])

    def test_hidden_strings_and_numbers(self):
        self.assertEqual(flatten_json_values(["name", ["Alice", "Bob"], 42]), ["name", "Alice", "Bob", 42])

    def test_hidden_empty_sublists(self):
        self.assertEqual(flatten_json_values([1, [], 2]), [1, 2])

    def test_hidden_single_nested_element(self):
        self.assertEqual(flatten_json_values([[5]]), [5])

    def test_hidden_all_empty_sublists(self):
        self.assertEqual(flatten_json_values([[], [], []]), [])

    def test_hidden_mixed_types(self):
        self.assertEqual(flatten_json_values([True, [None, 3.14], "hello", [False]]), [True, None, 3.14, "hello", False])

    def test_hidden_single_value(self):
        self.assertEqual(flatten_json_values([42]), [42])

if __name__ == '__main__':
    unittest.main()
